import sailpoint.object.Identity;

for(int i=0;i<this.variables.length;i++){
log.error("wf postman vvv  "+this.variables[i]);
}
Identity identity=null;
identity=context.getObjectByName(Identity.class, identityName);
return identity;

import sailpoint.object.*;
import sailpoint.api.*;

log.error("deummyStep-  triggered--");
String applicatioName="ActiveDirectory";
ProvisioningPlan plan =new ProvisioningPlan();
AccountRequest accReq=new AccountRequest();


List links=identity.getLinks();
for(Link link:links){
if(null!=link){
if(link.getApplicationName().equalsIgnoreCase(applicatioName)){
plan.setIdentity(identity);

accReq.setApplication(applicatioName);
accReq.setNativeIdentity(link.getNativeIdentity());
accReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Create);

List privilages=link.getAttribute("memberOf");
for(String str:privilages){
log.error(str);
}
if(privilages!=null){
accReq.add(new AttributeRequest("memberOf", ProvisioningPlan.Operation.Add,privilages));
plan.add(accReq);
}
}
}
}

log.error("--dummy wf exected--");

Provisioner pro = new Provisioner(context);
pro.execute(plan);
return plan;
